// ============================================================
// DECODE Pub/Sub push notification from Gmail
//
// Google Pub/Sub sends a base64-encoded message containing:
// { "emailAddress": "...", "historyId": "..." }
// We decode it and pass the historyId forward.
// ============================================================

const body = $input.item.json.body || $input.item.json;

if (!body.message || !body.message.data) {
  return [{ json: { skip: true, reason: 'No Pub/Sub message data found' } }];
}

let decoded;
try {
  const raw = Buffer.from(body.message.data, 'base64').toString('utf8');
  decoded = JSON.parse(raw);
} catch (e) {
  return [{ json: { skip: true, reason: 'Could not decode Pub/Sub message: ' + e.message } }];
}

const historyId = decoded.historyId;
const emailAddress = decoded.emailAddress || '';

if (!historyId) {
  return [{ json: { skip: true, reason: 'No historyId in decoded message' } }];
}

return [{ json: { historyId: String(historyId), emailAddress } }];

// Extract all new message IDs from the Gmail history response
const history = $input.item.json.history || [];

const messageIds = [];
for (const entry of history) {
  const added = entry.messagesAdded || [];
  for (const m of added) {
    if (m.message && m.message.id) {
      messageIds.push(m.message.id);
    }
  }
}

if (messageIds.length === 0) {
  return [{ json: { skip: true, reason: 'No new messages in this history batch' } }];
}

// Return one item per message ID so we can fetch each in parallel
return messageIds.map(id => ({ json: { messageId: id } }));

// ============================================================
// PARSE Gmail API message → extract subject, sender, body
//
// Gmail API returns email data in a structured format with
// headers and base64-encoded body parts.
// ============================================================

const msg = $input.item.json;
const headers = (msg.payload && msg.payload.headers) ? msg.payload.headers : [];

function getHeader(name) {
  const h = headers.find(h => h.name.toLowerCase() === name.toLowerCase());
  return h ? h.value : '';
}

function decodeBase64(encoded) {
  if (!encoded) return '';
  try {
    return Buffer.from(encoded.replace(/-/g, '+').replace(/_/g, '/'), 'base64').toString('utf8');
  } catch(e) { return ''; }
}

function extractBodyText(payload) {
  if (!payload) return '';
  if (payload.body && payload.body.data) {
    return decodeBase64(payload.body.data);
  }
  if (payload.parts) {
    for (const part of payload.parts) {
      if (part.mimeType === 'text/plain' && part.body && part.body.data) {
        return decodeBase64(part.body.data);
      }
    }
    // Fallback to HTML part
    for (const part of payload.parts) {
      if (part.mimeType === 'text/html' && part.body && part.body.data) {
        return decodeBase64(part.body.data);
      }
    }
  }
  return '';
}

const subject = getHeader('Subject');
const from    = getHeader('From');
const snippet = msg.snippet || '';
const body    = extractBodyText(msg.payload);

return [{ json: { subject, from, snippet, text: body, body, html: body } }];

// ============================================================
// FILTER — Only process LinkedIn 'new post' notification emails
// from monitored people.
//
// CONFIGURE: Add/remove names to control who triggers the workflow.
// ============================================================

const PEOPLE_TO_MONITOR = [
  "Sarah Goosse",          // (10) Sarah Goosse
  "Stephanie Courgey",     // linkedin.com/in/stephaniecourgey
  "Yann LeCun",            // linkedin.com/in/yann-lecun
  "Louis Claude",          // (11) Louis CLAUDE
  "Dylan Teixeira",        // (11) Dylan TEIXEIRA
  "Nicolas Hircq",         // linkedin.com/in/nicolas-hircq
  "Zeyneb Madi",           // linkedin.com/in/zeyneb-madi
  "Flav Roff",             // linkedin.com/in/flavroff — adjust if name differs
  "Ousmane Dicko",         // linkedin.com/in/ousmane-dicko
  "Brune Poirson",         // (11) Brune Poirson
  "Eric Djavid"            // linkedin.com/in/eric-djavid
];

// Post notification keywords (FR + EN)
const POST_KEYWORDS = [
  "a publié", "a partagé", "nouveau billet", "nouvelle publication",
  "posted", "shared", "new post", "published a post"
];

// Must come from LinkedIn notification sender
const LINKEDIN_SENDERS = [
  "updates@linkedin.com",
  "notifications-noreply@linkedin.com",
  "no-reply@linkedin.com",
  "member@linkedin.com",
  "linkedin.com"
];

const email = $input.item.json;
const from    = (email.from || "").toLowerCase();
const subject = (email.subject || "").toLowerCase();
const snippet = (email.snippet || "").toLowerCase();
const body    = (email.text || email.body || "").toLowerCase();
const combined = subject + " " + snippet + " " + body;

// Must be from LinkedIn
const isFromLinkedIn = LINKEDIN_SENDERS.some(s => from.includes(s));
if (!isFromLinkedIn) {
  return [{ json: { skip: true, reason: `Not from LinkedIn: ${email.from}` } }];
}

// Must mention a monitored person
const matchedPerson = PEOPLE_TO_MONITOR.find(name =>
  combined.includes(name.toLowerCase())
);

// Must be a post-type notification
const isPostNotif = POST_KEYWORDS.some(kw => combined.includes(kw));

if (!matchedPerson || !isPostNotif) {
  return [{ json: { skip: true, reason: `Not a monitored post notification. Subject: ${email.subject}` } }];
}

return [{
  json: {
    ...email,
    matched_person: matchedPerson,
    skip: false
  }
}];

// ============================================================
// EXTRACT POST URL from the LinkedIn notification email.
// ============================================================

const email = $input.item.json;
const person = email.matched_person || 'Author';

const text = [
  email.text || '',
  email.body || '',
  email.html || '',
  email.snippet || ''
].join(' ');

// 1. Direct LinkedIn post URL
const directMatch = text.match(/https:\/\/www\.linkedin\.com\/posts\/[\w%\-._~:/?#[\]@!$&'()*+,;=]+/i);
if (directMatch) {
  return { json: { post_url: directMatch[0], person, email_subject: email.subject } };
}

// 2. Feed/update URL
const feedMatch = text.match(/https:\/\/www\.linkedin\.com\/feed\/update\/[\w%\-._~:/?#[\]@!$&'()*+,;=]+/i);
if (feedMatch) {
  return { json: { post_url: feedMatch[0], person, email_subject: email.subject } };
}

// 3. LinkedIn tracking redirect
const trackMatch = text.match(/https:\/\/(lnkd\.in|www\.linkedin\.com\/comm)[\w%\-._~:/?#[\]@!$&'()*+,;=]+/i);
if (trackMatch) {
  return { json: { post_url: trackMatch[0], person, email_subject: email.subject } };
}

// 4. Any linkedin.com URL
const anyMatch = text.match(/https:\/\/www\.linkedin\.com\/[\w%\-._~:/?#[\]@!$&'()*+,;=]{10,}/i);
if (anyMatch) {
  return { json: { post_url: anyMatch[0], person, email_subject: email.subject } };
}

return { json: { skip: true, reason: 'No LinkedIn URL found in email', subject: email.subject } };

const originalUrl = $('Extract Post URL from Email').item.json.post_url || '';
const person      = $('Extract Post URL from Email').item.json.person || 'Author';
const subject     = $('Extract Post URL from Email').item.json.email_subject || '';
const pageHtml    = $input.item.json.data || '';
const resolvedUrl = $input.item.json.url || originalUrl;

let urn = '';
const ugc = resolvedUrl.match(/ugcPost[-:]([0-9]+)/);
const shr = resolvedUrl.match(/share[-:]([0-9]+)/);
const act = resolvedUrl.match(/activity[-:]([0-9]+)/);

if (ugc)      urn = 'urn:li:ugcPost:'  + ugc[1];
else if (shr) urn = 'urn:li:share:'   + shr[1];
else if (act) urn = 'urn:li:activity:' + act[1];

if (!urn) {
  const u2 = originalUrl.match(/ugcPost[-:]([0-9]+)/);
  const s2 = originalUrl.match(/share[-:]([0-9]+)/);
  const a2 = originalUrl.match(/activity[-:]([0-9]+)/);
  if (u2)      urn = 'urn:li:ugcPost:'  + u2[1];
  else if (s2) urn = 'urn:li:share:'   + s2[1];
  else if (a2) urn = 'urn:li:activity:' + a2[1];
}

if (!urn) {
  return { json: { skip: true, reason: 'Could not extract URN from: ' + resolvedUrl } };
}

let post_text = '';
const ogDesc = pageHtml.match(/<meta[^>]+property=["']og:description["'][^>]+content=["']([^"']+)["']/i);
if (ogDesc) post_text = ogDesc[1];
if (!post_text) {
  const metaDesc = pageHtml.match(/<meta[^>]+name=["']description["'][^>]+content=["']([^"']+)["']/i);
  if (metaDesc) post_text = metaDesc[1];
}
if (!post_text) post_text = subject;

post_text = post_text
  .replace(/&amp;/g, '&').replace(/&lt;/g, '<').replace(/&gt;/g, '>')
  .replace(/&quot;/g, '"').replace(/&#39;/g, "'")
  .replace(/\\n/g, ' ').trim();

return { json: { urn, post_url: resolvedUrl || originalUrl, post_text, author: person } };

return {
  json: {
    urn:      $('Extract URN + Post Text').item.json.urn,
    post_url: $('Extract URN + Post Text').item.json.post_url,
    comment:  $input.item.json.output
  }
};

